import type { MainModule } from '../../build/javascript/wasm/cp_sat_runtime.js';

type CpSatModuleFactory = (moduleArg?: Record<string, unknown>) => Promise<MainModule>;

let cpSatModuleFactoryPromise: Promise<CpSatModuleFactory> | null = null;

export function loadCpSatModuleFactory(): Promise<CpSatModuleFactory> {
  if (!cpSatModuleFactoryPromise) {
    cpSatModuleFactoryPromise = import('../../build/javascript/wasm/cp_sat_runtime.js').then((module) => {
      const factory = module?.default as CpSatModuleFactory | undefined;
      if (!factory) {
        throw new Error('cp_sat_runtime factory is unavailable.');
      }
      return factory;
    });
  }
  return cpSatModuleFactoryPromise;
}

export type { MainModule };
